<?php namespace App\Notifications; use App\Models\Post; use Illuminate\Bus\Queueable; use Illuminate\Contracts\Queue\ShouldQueue; use Illuminate\Notifications\Notification; class PostScheduleReminderNotification extends Notification implements ShouldQueue { use Queueable; public function __construct(public Post $post) {} public function via(object $notifiable): array { return ['database']; } public function toDatabase(object $notifiable): array { $menit = now()->diffInMinutes($this->post->scheduled_at); return [ 'type' => 'schedule', 'title' => '⏰ Posting Akan Segera Dipublikasikan', 'message' => "Post \"{$this->post->caption_preview}\" akan dipublish dalam {$menit} menit lagi.", 'post_id' => $this->post->id, 'platform' => $this->post->platform, 'caption' => $this->post->caption, 'scheduled_at' => $this->post->scheduled_at->format('d M Y H:i'), 'account_name' => $this->post->socialAccount->account_name ?? '-', ]; } }